import React, { useState } from 'react';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

export default function DataUpload() {
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [result, setResult] = useState(null);

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
    setResult(null);
  };

  const handleUpload = async () => {
    if (!file) return;

    setUploading(true);
    setResult('Reading file...');

    const reader = new FileReader();
    reader.onload = async (e) => {
      const text = e.target?.result;

      try {
        // Send to AI for analysis
        const response = await fetch(`${API_URL}/ai_chat`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ 
            message: `Analyze these property listings and give me insights:\n\n${text}`
          })
        });
        const data = await response.json();
        setResult(data.response || data);
      } catch (err) {
        setResult({ error: err.message });
      }
      setUploading(false);
    };

    reader.readAsText(file);
  };

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto' }}>
      <h2>📁 Upload Property Data</h2>
      <p style={{ color: '#8b949e', marginBottom: '1.5rem' }}>
        Upload CSV or paste property data for AI analysis
      </p>

      <div style={{ 
        background: 'rgba(22,27,34,0.8)', 
        border: '1px solid rgba(139,148,158,0.15)', 
        borderRadius: '16px', 
        padding: '2rem',
        marginBottom: '1.5rem'
      }}>
        <div className="form-group">
          <label>Select CSV File</label>
          <input 
            type="file" 
            accept=".csv,.txt"
            onChange={handleFileChange}
            style={{
              background: 'rgba(0,0,0,0.4)',
              border: '1px solid rgba(139,148,158,0.25)',
              borderRadius: '10px',
              padding: '0.875rem',
              color: '#fff',
              width: '100%'
            }}
          />
        </div>

        <button 
          onClick={handleUpload} 
          disabled={!file || uploading}
          style={{
            background: 'linear-gradient(135deg, #238636 0%, #2ea043 100%)',
            color: 'white',
            border: 'none',
            padding: '0.875rem 2rem',
            borderRadius: '10px',
            fontWeight: '600',
            cursor: 'pointer',
            width: '100%',
            marginTop: '1rem',
            opacity: (!file || uploading) ? 0.5 : 1
          }}
        >
          {uploading ? 'Analyzing...' : 'Analyze Properties'}
        </button>
      </div>

      {result && (
        <div style={{ 
          background: 'rgba(0,0,0,0.3)', 
          borderRadius: '12px', 
          padding: '1.5rem',
          textAlign: 'left'
        }}>
          <h3 style={{ color: '#e6edf3', marginBottom: '1rem' }}>Analysis Results:</h3>
          <pre style={{ 
            whiteSpace: 'pre-wrap', 
            color: '#e6edf3',
            fontSize: '0.9rem',
            fontFamily: 'inherit'
          }}>
            {typeof result === 'string' ? result : JSON.stringify(result, null, 2)}
          </pre>
        </div>
      )}

      <div style={{ marginTop: '2rem', textAlign: 'left', color: '#6e7681', fontSize: '0.85rem' }}>
        <h4 style={{ color: '#8b949e' }}>Example CSV format:</h4>
        <code>
address,price,bedrooms,bathrooms,sqft<br/>
123 Main St,350000,3,2,1800<br/>
456 Oak Ave,425000,4,2.5,2200
        </code>
      </div>
    </div>
  );
}
